#include <stdio.h>
#include <time.h>
#include <string.h>

/**
 * Logs an error message to the specified log file with timestamp and
 * detailed debugging information.
 *
 * @param logfile    An already-opened FILE* for the log file.
 * @param source     The source module or function name where the error occurred.
 * @param line       The line number where the error occurred.
 * @param error_msg  The error message (may contain user-supplied input).
 * @return           0 on success, -1 on failure.
 *
 * Security note: error_msg is never used as a format string. It is always
 * passed as a "%s" argument to fprintf() to prevent format string attacks.
 */
int log_error(FILE *logfile, const char *source, int line, const char *error_msg)
{
    if (logfile == NULL || error_msg == NULL) {
        return -1;
    }

    /* Get current timestamp */
    time_t now = time(NULL);
    struct tm *tm_info = localtime(&now);
    char time_buf[64];

    if (tm_info == NULL) {
        strncpy(time_buf, "unknown-time", sizeof(time_buf) - 1);
        time_buf[sizeof(time_buf) - 1] = '\0';
    } else {
        strftime(time_buf, sizeof(time_buf), "%Y-%m-%d %H:%M:%S", tm_info);
    }

    /*
     * SECURE: error_msg is passed as an argument to "%s", NOT as the format
     * string itself. This prevents format string vulnerabilities where
     * user-controlled input containing %s, %x, %n, etc. could read from or
     * write to the stack.
     *
     * INSECURE (DO NOT USE):
     *     fprintf(logfile, error_msg);          // error_msg IS the format string
     *     fprintf(logfile, error_msg, ...);     // still vulnerable
     *
     * SECURE (what we do below):
     *     fprintf(logfile, "[%s] [%s:%d] ERROR: %s\n", time_buf, source, line, error_msg);
     */
    const char *safe_source = (source != NULL) ? source : "unknown";

    int ret = fprintf(logfile, "[%s] [%s:%d] ERROR: %s\n",
                      time_buf, safe_source, line, error_msg);

    if (ret < 0) {
        return -1;
    }

    /* Flush immediately so the log entry is persisted even if a crash follows */
    fflush(logfile);

    return 0;
}

